const functions = require('firebase-functions');
const { Storage } = require('@google-cloud/storage');
const express = require('express');
const app = express();
const storage = new Storage();

app.get('/serve-file/:fileName', async (req, res) => {
    const { bucket, filePath } = req.query;

    if (!bucket || !filePath) {
        return res.status(400).send('Missing bucket or filePath query parameter');
    }

    const file = storage.bucket(bucket).file(`${filePath}/${req.params.fileName}`);
    const [exists] = await file.exists();

    if (!exists) {
        return res.status(404).send('File not found');
    }

    res.type(file.metadata.contentType);
    file.createReadStream().pipe(res).on('error', (err) => {
        console.error(err);
        res.status(500).send('Error streaming file');
    });
});

exports.serveFile = functions.https.onRequest(app);